mapper.insert:
INSERT INTO BOARD_MASTER
(
	BOARD_TYPE
  , BOARD_NM
  , BOARD_PATH
  , USE_YN
  , COMMENT_YN
  , BOARD_NOTE
  , REG_NO
  , REG_DATE
  , UP_NO
  , UP_DATE
)
VALUES
(
	#{boardType}
  , #{boardNm}
  , #{boardPath}
  , #{useYn}
  , #{commentYn}
  , #{boardNote}
  , '1'
  , NOW()
  , '1'
  , NOW()
)

mapper.update:
UPDATE
	BOARD_MASTER
SET
	BOARD_TYPE = #{boardType}
  , BOARD_NM = #{boardNm}
  , BOARD_PATH = #{boardPath}
  , USE_YN = #{useYn}
  , COMMENT_YN = #{commentYn}
  , BOARD_NOTE = #{boardNote}
  , UP_NO = '1'
  , UP_DATE = NOW()
WHERE
		1=1

	AND BOARD_NO = #{boardNo}

